// Aggregate data from last month
const now = new Date();
const mesesPT = ['janeiro','fevereiro','marco','abril','maio','junho','julho','agosto','setembro','outubro','novembro','dezembro'];
const lastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const monthName = mesesPT[lastMonth.getMonth()] + ' de ' + lastMonth.getFullYear();

// Clients list (same as other workflows) for aggregating GHL data
const clients = [
  { name: 'Alfa Construction Inc.', ghlKey: 'YOUR_GHL_KEY' },
  { name: 'Wolfs Siding Inc', ghlKey: 'YOUR_GHL_KEY' },
  { name: 'RS Development Group', ghlKey: 'YOUR_GHL_KEY' },
  { name: 'Mass HVAC', ghlKey: 'YOUR_GHL_KEY' },
  { name: 'Maia Construction Inc', ghlKey: 'YOUR_GHL_KEY' },
  { name: 'JH Painting Services', ghlKey: 'YOUR_GHL_KEY' },
  { name: 'Dorys Cleaning Services', ghlKey: 'YOUR_GHL_KEY' }
];

return clients.map(c => ({ json: { ...c, monthName } }));

// Aggregate: for each client, count new leads in last 30 days
return $input.all().map((item, idx) => {
  const client = $('Lista de Clientes').all()[idx]?.json || {};
  const contacts = item.json?.contacts || [];
  const now = Date.now();
  const thirtyAgo = now - 30*24*60*60*1000;
  const yesterdayEnd = now - 1*24*60*60*1000;
  const last30 = contacts.filter(c => {
    const t = c.dateAdded ? new Date(c.dateAdded).getTime() : 0;
    return t >= thirtyAgo && t <= yesterdayEnd;
  });
  const formLeads = last30.filter(c => {
    const src = (c.source||'').toLowerCase();
    return src.includes('form') || src.includes('site');
  });
  return { json: {
    name: client.name,
    totalContacts30d: last30.length,
    formLeads30d: formLeads.length,
    monthName: client.monthName
  }};
});

// Merge all clients into one summary
const items = $input.all().map(i => i.json);
const monthName = items[0]?.monthName || 'mes passado';
const totalClients = items.length;
const totalLeads = items.reduce((s, c) => s + (c.formLeads30d || 0), 0);
const totalContacts = items.reduce((s, c) => s + (c.totalContacts30d || 0), 0);
const avgPerClient = totalClients > 0 ? (totalLeads / totalClients).toFixed(1) : 0;

// Top/bottom performers
const sorted = [...items].sort((a,b) => (b.formLeads30d||0) - (a.formLeads30d||0));
const topClient = sorted[0];
const bottomClient = sorted[sorted.length - 1];

// Build summary rows
const clientRows = items.map(c => 
  '<tr><td style="padding:8px;border-bottom:1px solid #e5e5e5;">' + c.name + '</td>' +
  '<td style="padding:8px;border-bottom:1px solid #e5e5e5;text-align:center;font-weight:700;color:#1a237e;">' + (c.formLeads30d||0) + '</td>' +
  '<td style="padding:8px;border-bottom:1px solid #e5e5e5;text-align:center;color:#6b7280;">' + (c.totalContacts30d||0) + '</td></tr>'
).join('');

const html = '<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;padding:20px;color:#333;background:#f5f5f5;">' +
'<div style="background:linear-gradient(135deg,#0d1b2a,#1a237e);padding:30px;border-radius:12px 12px 0 0;text-align:center;">' +
'<h1 style="color:#ffd700;margin:0;font-size:22px;">Galaxy IT &amp; Marketing</h1>' +
'<p style="color:rgba(255,255,255,0.7);margin:8px 0 0;font-size:14px;">Relatorio Interno - Resumo de ' + monthName + '</p>' +
'</div>' +
'<div style="background:#fff;padding:30px;border:1px solid #e5e5e5;border-top:none;">' +
'<table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="margin-bottom:24px;"><tr>' +
'<td width="33%" style="padding:0 4px;text-align:center;"><div style="background:#f8f9fa;padding:18px 8px;border-radius:8px;border-top:3px solid #ffd700;">' +
'<div style="font-size:28px;font-weight:800;color:#1a237e;">' + totalLeads + '</div>' +
'<div style="font-size:9px;color:#888;margin-top:4px;text-transform:uppercase;">Total Leads</div></div></td>' +
'<td width="33%" style="padding:0 4px;text-align:center;"><div style="background:#f8f9fa;padding:18px 8px;border-radius:8px;border-top:3px solid #2e7d32;">' +
'<div style="font-size:28px;font-weight:800;color:#1a237e;">' + totalClients + '</div>' +
'<div style="font-size:9px;color:#888;margin-top:4px;text-transform:uppercase;">Clientes Ativos</div></div></td>' +
'<td width="33%" style="padding:0 4px;text-align:center;"><div style="background:#f8f9fa;padding:18px 8px;border-radius:8px;border-top:3px solid #1a237e;">' +
'<div style="font-size:28px;font-weight:800;color:#1a237e;">' + avgPerClient + '</div>' +
'<div style="font-size:9px;color:#888;margin-top:4px;text-transform:uppercase;">Media por Cliente</div></div></td>' +
'</tr></table>' +
'<h3 style="color:#1a237e;margin-top:24px;">Desempenho por cliente</h3>' +
'<table style="width:100%;border-collapse:collapse;font-size:14px;">' +
'<thead><tr style="background:#f8f9fa;"><th style="padding:10px 8px;text-align:left;border-bottom:2px solid #1a237e;">Cliente</th>' +
'<th style="padding:10px 8px;text-align:center;border-bottom:2px solid #1a237e;">Leads</th>' +
'<th style="padding:10px 8px;text-align:center;border-bottom:2px solid #1a237e;">Total Contatos</th></tr></thead>' +
'<tbody>' + clientRows + '</tbody></table>' +
(topClient ? '<div style="background:#f0fdf4;padding:14px;margin-top:20px;border-left:4px solid #16a34a;border-radius:4px;"><b>Melhor desempenho:</b> ' + topClient.name + ' com ' + topClient.formLeads30d + ' leads</div>' : '') +
(bottomClient && bottomClient !== topClient ? '<div style="background:#fef2f2;padding:14px;margin-top:8px;border-left:4px solid #dc2626;border-radius:4px;"><b>Precisa atencao:</b> ' + bottomClient.name + ' com apenas ' + bottomClient.formLeads30d + ' leads</div>' : '') +
'</div>' +
'<div style="background:#f8f9fa;padding:20px;border-radius:0 0 12px 12px;text-align:center;border:1px solid #e5e5e5;border-top:none;">' +
'<p style="margin:0;font-size:12px;color:#888;">Relatorio gerado automaticamente pela Galaxy IT</p>' +
'</div></body></html>';

return [{ json: {
  monthName,
  totalClients, totalLeads, totalContacts, avgPerClient,
  topClient, bottomClient,
  html,
  subject: 'Resumo Interno Galaxy IT - ' + monthName + ' (' + totalLeads + ' leads em ' + totalClients + ' clientes)'
}}];
